(window.webpackJsonp=window.webpackJsonp||[]).push([[250],{877:function(n,r){n.exports="\x3c!-- \r\ntitle: 42-Socket编程\r\nsort: \r\n--\x3e \r\n# Socket编程\r\n\r\n## 入门\r\n\r\n### 创建tcp/udp套接字\r\n\r\n```python\r\nimport socket\r\n\r\nudp_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\r\nupd_socket.close()\r\n```\r\n\r\n`socket.socker(AdressFamily, Type)`\r\n\r\n> 参数一：\r\n>\r\n> `socket.AF_INET` IPv4\r\n>\r\n> 参数二：\r\n>\r\n> `socket.SOCK_DGRAM` UDP\r\n>\r\n> `SOCK_STREAM` TCP\r\n\r\n### 使用 \r\n\r\n#### 发送\r\n\r\n```python\r\nimport socket\r\n\r\nudp = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)\r\n\r\nudp.sendto(\"hello\".encode(), (\"192.168.0.101\",777))\r\nudp.close()\r\n```\r\n\r\n#### 接收\r\n\r\n```python\r\nimport socket\r\n\r\nudp = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)\r\nudp.bind(('', 9999))\r\n\r\nudp.sendto(\"hello\".encode(), ('127.0.0.1',40404))\r\n\r\nrecv = udp.recvfrom(1024)\r\nprint(recv[0].decode('gbk'))\r\n\r\nudp.close()\r\n```\r\n\r\n### 广播\r\n\r\n> 广播地址：255.255.255.255 xxx.xxx.xxx.255\r\n\r\n```python\r\n# SOL_SOCKET 当前套接字\r\n# SO_BROADCAST 广播\r\n# 设置套接字参数（套接字，参数名，参数） \r\nudp.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, True)\r\nudp.sendto(\"hello\".encode(), ('255.255.255.255',8080))\r\n\r\n```\r\n\r\n## TCP\r\n\r\n### 客户端\r\n\r\n```python\r\nimport socket\r\n\r\ntcp = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\r\n# 服务端信息\r\ntcp.connect(('127.0.0.1',8080))\r\n# 发送\r\ntcp.send('hi~'.encode('gbk'))\r\n\r\ncontent = tcp.recv(1024).decode('gbk')\r\nprint(content)\r\n```\r\n\r\n### 服务端\r\n\r\n```python\r\nimport socket\r\n\r\ntcp = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\r\n# 绑定地址\r\ntcp.bind(('',8080))\r\n# 设置监听，不得主动发送数据，最大连接数为128\r\ntcp.listen(128)\r\n# 自动进入阻塞状态，等待连接，返回socket对象\r\n# recv[0]为socket对象，[1]为客户端地址\r\nclient_socket, client_addr = tcp.accept()\r\n# 设定接收\r\nrecv_text = client_socket.recv(1024).decode('gbk')\r\nprint(recv_text)\r\n\r\nclient_socket.close()\r\ntcp.close\r\n```\r\n\r\n#### 增强\r\n\r\n```python\r\nimport socket\r\n\r\ntcp = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\r\ntcp.bind(('',8080))\r\ntcp.listen(128)\r\n\r\nclient_socket, client_addr = tcp.accept()\r\n\r\nwhile True:\r\n    recv_text = client_socket.recv(1024).decode('gbk')\r\n    if recv_text:\r\n        print(recv_text)\r\n        client_socket.send('I get your message.'.encode())\r\n    else:\r\n        print(\"Client Close!\")\r\n        break\r\n\r\nclient_socket.close()\r\ntcp.close()\r\n```\r\n\r\n- 地址重用\r\n\r\n  ```python\r\n  # SOL_SOCKET 当前套接字\r\n  # socket.SO_REUSEADDR 重用地址 reuseaddr\r\n  # 设置套接字参数（套接字，参数名，参数）\r\n  tcp.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, True)  python、python\r\n  ```\r\n\r\n\r\n## HTTP\r\n\r\n### 基本\r\n\r\n```python\r\nimport socket\r\n\r\nhttp_header = 'HTTP/1.1 200 OK\\r\\n\\r\\n'\r\ncontent = '<h1>Hello</h1>'\r\nresponse = http_header+content\r\n\r\ntcp = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\r\ntcp.bind(('',8080))\r\ntcp.listen(128)\r\n\r\nclient_socket, client_addr = tcp.accept()\r\nrecv_text = client_socket.recv(1024).decode('gbk')\r\nif recv_text:\r\n    print(recv_text)\r\n    client_socket.send(response.encode())\r\nelse:\r\n    print(\"Client Close!\")\r\n\r\nclient_socket.close()\r\ntcp.close()\r\n```\r\n\r\n"}}]);